/**
 * Toastify JS 1.12.0
 * Minimal local copy to replace CDN
 */
(function(global) {
  'use strict';

  const Toastify = function(options) {
    return new Toast(options);
  };

  const Toast = function(options) {
    options = options || {};
    this.text = options.text || 'Notification';
    this.duration = options.duration == undefined ? 3000 : options.duration;
    this.selector = options.selector;
    this.callback = options.callback;
    this.destination = options.destination;
    this.newWindow = options.newWindow || false;
    this.close = options.close || false;
    this.gravity = options.gravity || 'toastify-top';
    this.position = options.position || 'toastify-right';
    this.backgroundColor = options.backgroundColor;
    this.avatar = options.avatar || '';
    this.className = options.className || '';
    this.stopOnFocus = options.stopOnFocus == undefined ? true : options.stopOnFocus;
    this.style = options.style || {};
    
    if(options.escapeMarkup != undefined) {
      this.escapeMarkup = options.escapeMarkup;
    } else {
      this.escapeMarkup = true;
    }

    this.text = this.escapeMarkup ? escapeHtml(this.text) : this.text;
    this.showToast();
  };

  const escapeHtml = function(text) {
    const map = {
      '&': '&amp;',
      '<': '&lt;',
      '>': '&gt;',
      '"': '&quot;',
      "'": '&#039;'
    };
    return text.replace(/[&<>"']/g, m => map[m]);
  };

  Toast.prototype.showToast = function() {
    const el = document.getElementById('toastify-container');
    if(!el) {
      this.getContainer();
    }

    const toastElement = document.createElement('div');
    toastElement.className = 'toastify on ' + this.className + ' ' + this.gravity + ' ' + this.position;

    if(this.backgroundColor) {
      toastElement.style.backgroundColor = this.backgroundColor;
    }
    for(const key in this.style) {
      toastElement.style[key] = this.style[key];
    }

    if(this.avatar != '') {
      const avatarElement = document.createElement('img');
      avatarElement.src = this.avatar;
      toastElement.appendChild(avatarElement);
    }

    const spanElement = document.createElement('span');
    spanElement.innerHTML = this.text;
    toastElement.appendChild(spanElement);

    if(this.close === true) {
      const closeElement = document.createElement('button');
      closeElement.className = 'toast-close';
      closeElement.innerHTML = '✕';
      toastElement.appendChild(closeElement);

      closeElement.addEventListener('click', () => {
        this.removeElement(toastElement);
      });
    }

    const container = document.getElementById('toastify-container');
    if(this.selector) {
      const customContainer = document.querySelector(this.selector);
      if(customContainer) {
        customContainer.appendChild(toastElement);
      }
    } else {
      container.appendChild(toastElement);
    }

    this.toastElement = toastElement;

    if(this.stopOnFocus && this.duration > 0) {
      const self = this;
      toastElement.addEventListener('mouseover', function() {
        self.pauseToast();
      });
      toastElement.addEventListener('mouseleave', function() {
        self.resumeToast();
      });
    }

    if(this.duration > 0) {
      this.timeoutId = setTimeout(() => {
        this.removeElement(toastElement);
      }, this.duration);
    }

    if(typeof this.callback === 'function') {
      this.callback.call(toastElement);
    }

    return this;
  };

  Toast.prototype.getContainer = function() {
    let container = document.getElementById('toastify-container');
    if(!container) {
      container = document.createElement('div');
      container.id = 'toastify-container';
      container.className = 'toastify-container';
      document.body.appendChild(container);
    }
    return container;
  };

  Toast.prototype.removeElement = function(toastElement) {
    if(this.timeoutId) {
      clearTimeout(this.timeoutId);
    }
    toastElement.classList.remove('on');
    setTimeout(() => {
      if(toastElement.parentElement) {
        toastElement.parentElement.removeChild(toastElement);
      }
    }, 400);
  };

  Toast.prototype.pauseToast = function() {
    if(this.timeoutId) {
      clearTimeout(this.timeoutId);
    }
  };

  Toast.prototype.resumeToast = function() {
    const self = this;
    if(this.duration > 0) {
      this.timeoutId = setTimeout(() => {
        self.removeElement(self.toastElement);
      }, this.duration);
    }
  };

  Toastify.showToast = function(options) {
    return new Toast(options);
  };

  if(typeof module !== 'undefined' && module.exports) {
    module.exports = Toastify;
  }

  global.Toastify = Toastify;
})(typeof window !== 'undefined' ? window : global);
